// Parse Lever API response, filter by title keywords AND geography
// LEVER RETURNS A FLAT ARRAY — n8n splits it into individual items (one per job)
// So we use $input.all() instead of $input.first().json

const allInputs = $input.all();

const prep = $('Prepare Company Data').item.json;
const companyName = prep.companyName;
const keywordsRaw = prep.titleKeywords || '';

if (!companyName) {
  throw new Error('Company Name missing from Prepare Company Data node.');
}

// Dynamic geography from Profile table
const profileData = $('Get Profile').first().json;
const geoField = profileData.fields 
  ? profileData.fields['Target Geography'] 
  : profileData['Target Geography'];
const userGeographies = Array.isArray(geoField) ? geoField : ['Remote Global'];

const GEO_CONFIG = {
  'Canada': {
    countries: ['canada'],
    substrings: ['canada', 'toronto', 'vancouver', 'montreal', 'ottawa', 'calgary', 'mississauga', 'edmonton', 'waterloo', 'quebec'],
    isoCodes: ['CA']
  },
  'USA': {
    countries: ['united states', 'usa', 'us'],
    substrings: ['united states', 'new york', 'san francisco', 'los angeles', 'seattle', 'chicago', 'austin', 'boston', 'denver'],
    isoCodes: ['US']
  },
  'Remote Global': {
    countries: [],
    substrings: ['remote worldwide', 'worldwide', 'global remote', 'anywhere in the world', 'fully remote global'],
    exactLocations: ['remote', 'worldwide', 'global', 'anywhere', 'remote - global', 'remote global'],
    isoCodes: []
  },
  'Remote North America': {
    countries: [],
    substrings: ['remote north america', 'remote - north america', 'remote na', 'remote us/canada', 'remote us and canada', 'remote (na)', 'remote - us', 'remote - canada'],
    exactLocations: ['remote - north america', 'remote north america'],
    isoCodes: []
  },
  'Remote Canada': {
    countries: [],
    substrings: ['remote canada', 'remote - canada'],
    exactLocations: ['remote - canada', 'remote canada'],
    isoCodes: []
  },
  'UK': {
    countries: ['united kingdom', 'uk', 'britain'],
    substrings: ['united kingdom', 'london', 'manchester', 'edinburgh'],
    isoCodes: ['GB']
  },
  'Germany': {
    countries: ['germany'],
    substrings: ['germany', 'berlin', 'munich', 'hamburg', 'frankfurt'],
    isoCodes: ['DE']
  },
  'Netherlands': {
    countries: ['netherlands'],
    substrings: ['netherlands', 'amsterdam', 'rotterdam', 'the hague'],
    isoCodes: ['NL']
  },
  'France': {
    countries: ['france'],
    substrings: ['france', 'paris', 'lyon', 'marseille'],
    isoCodes: ['FR']
  },
  'Ireland': {
    countries: ['ireland'],
    substrings: ['ireland', 'dublin', 'cork'],
    isoCodes: ['IE']
  },
  'Australia': {
    countries: ['australia'],
    substrings: ['australia', 'sydney', 'melbourne', 'brisbane'],
    isoCodes: ['AU']
  },
  'Singapore': {
    countries: ['singapore'],
    substrings: ['singapore'],
    isoCodes: ['SG']
  },
  'India': {
    countries: ['india'],
    substrings: ['india', 'bangalore', 'bengaluru', 'mumbai', 'hyderabad', 'pune', 'delhi', 'gurgaon', 'noida'],
    isoCodes: ['IN']
  },
  'EMEA': {
    countries: ['germany', 'france', 'spain', 'italy', 'netherlands', 'ireland', 'poland'],
    substrings: ['emea', 'europe', 'berlin', 'paris', 'amsterdam', 'dublin', 'madrid'],
    isoCodes: ['DE', 'FR', 'ES', 'IT', 'NL', 'IE', 'PL']
  },
  'Remote Europe': {
    countries: [],
    substrings: ['remote europe', 'remote - europe', 'remote emea', 'remote - emea'],
    exactLocations: ['remote - europe', 'remote europe'],
    isoCodes: []
  },
  'APAC': {
    countries: ['australia', 'singapore', 'japan', 'south korea'],
    substrings: ['apac', 'asia', 'singapore', 'tokyo', 'sydney'],
    isoCodes: ['AU', 'SG', 'JP', 'KR']
  },
  'Remote APAC': {
    countries: [],
    substrings: ['remote apac', 'remote - apac', 'remote asia', 'remote - asia'],
    exactLocations: ['remote - apac', 'remote apac'],
    isoCodes: []
  },
  'Remote LATAM': {
    countries: [],
    substrings: ['remote latam', 'remote - latam', 'remote latin america', 'remote - latin america'],
    exactLocations: ['remote - latam', 'remote latam'],
    isoCodes: []
  }
};

// Build active match sets from user's chosen geographies
const activeCountries = new Set();
const activeSubstrings = new Set();
const activeExactLocations = new Set();
const activeIsoCodes = new Set();
for (const geo of userGeographies) {
  const cfg = GEO_CONFIG[geo];
  if (!cfg) continue;
  (cfg.countries || []).forEach(c => activeCountries.add(c.toLowerCase()));
  (cfg.substrings || []).forEach(s => activeSubstrings.add(s.toLowerCase()));
  (cfg.exactLocations || []).forEach(e => activeExactLocations.add(e.toLowerCase()));
  (cfg.isoCodes || []).forEach(i => activeIsoCodes.add(i.toUpperCase()));
}

// Check if a single location string matches any user geography
const locationMatches = (locationString) => {
  const loc = (locationString || '').toLowerCase().trim();
  if (!loc) return false;

  if (activeExactLocations.has(loc)) return true;

  for (const c of activeCountries) {
    if (loc === c || loc.startsWith(c + ',') || loc.endsWith(' ' + c) || loc.includes(', ' + c)) {
      return true;
    }
  }

  for (const sub of activeSubstrings) {
    if (loc.includes(sub)) return true;
  }

  return false;
};

// Lever country code check — now dynamic from GEO_CONFIG
const countryCodeMatches = (countryCode) => {
  if (!countryCode) return false;
  return activeIsoCodes.has(countryCode.toUpperCase());
};

// Main geography matcher for Lever
const matchesGeography = (job) => {
  if (countryCodeMatches(job.country)) return true;

  const primaryLocation = (job.categories && job.categories.location) || '';
  if (locationMatches(primaryLocation)) return true;

  if (job.categories && Array.isArray(job.categories.allLocations)) {
    for (const loc of job.categories.allLocations) {
      if (locationMatches(loc)) return true;
    }
  }

  return false;
};

const keywords = keywordsRaw
  .split(',')
  .map(k => k.trim().toLowerCase())
  .filter(k => k.length > 0);

const jobs = allInputs.map(item => item.json);

if (jobs.length === 0) {
  return [{ json: { _empty: true, _company: companyName } }];
}

const titleFiltered = jobs.filter(job => {
  if (keywords.length === 0) return true;
  const title = (job.text || '').toLowerCase();
  return keywords.some(kw => title.includes(kw));
});

const filtered = titleFiltered.filter(matchesGeography);

if (filtered.length === 0) {
  return [{ json: { _empty: true, _company: companyName } }];
}

const fnv1aHash = (str) => {
  let hash = 0x811c9dc5;
  for (let i = 0; i < str.length; i++) {
    hash ^= str.charCodeAt(i);
    hash = Math.imul(hash, 0x01000193);
  }
  return (hash >>> 0).toString(16).padStart(8, '0');
};

const items = filtered.map(job => {
  const title = job.text || 'Untitled';
  const location = (job.categories && job.categories.location) || 'Not specified';
  const applyLink = job.hostedUrl || job.applyUrl || '';

  let description = job.descriptionPlain || '';
  if (Array.isArray(job.lists) && job.lists.length > 0) {
    const listsText = job.lists.map(section => {
      const header = section.text || '';
      const content = (section.content || '')
        .replace(/<li>/gi, '\n- ')
        .replace(/<\/li>/gi, '')
        .replace(/<[^>]+>/g, '')
        .trim();
      return header + '\n' + content;
    }).join('\n\n');
    description = description + '\n\n' + listsText;
  }
  if (!description.trim()) {
    description = '[Description not available]';
  }

  let salaryNote = '';
  if (job.salaryRange && job.salaryRange.min != null) {
    const currency = job.salaryRange.currency || '';
    const interval = job.salaryRange.interval || '';
    salaryNote = `${currency} ${job.salaryRange.min.toLocaleString()} - ${job.salaryRange.max.toLocaleString()} ${interval}`.trim();
  }

  if (salaryNote) {
    description = description + '\n\nSalary: ' + salaryNote;
  }

  const hashInput = `${title}|${companyName}|${applyLink}`;
  const jobId = fnv1aHash(hashInput) + '-' + companyName.substring(0, 3).toLowerCase();

  return {
    json: {
      jobId: jobId,
      jobTitle: title,
      company: companyName,
      location: location,
      applyLink: applyLink,
      jobDescription: description,
      source: 'Lever',
      sourceQuery: companyName,
      sourceTag: 'Tracked Company',
      discoveryDate: new Date().toISOString().split('T')[0]
    }
  };
});

return items;

// Aggregate results from all company loops into a single deduplicated list
// This runs after Loop Companies completes all iterations

const allItems = $input.all();

// Filter out summary-only items (those with _empty flag) and keep real job items
const realJobs = allItems.filter(item => !item.json._empty && item.json.jobId);

// In-memory deduplication by jobId (in case same job appeared in multiple companies, unlikely but defensive)
const seen = new Set();
const unique = [];
for (const item of realJobs) {
  if (!seen.has(item.json.jobId)) {
    seen.add(item.json.jobId);
    unique.push(item);
  }
}

return unique;

// Filter aggregated jobs against existing Job IDs in Pipeline (deduplication)

const aggregatedJobs = $('Aggregate All Jobs').all();
const existingRecords = $('Get Existing Job IDs').all();

const existingIds = new Set();
for (const record of existingRecords) {
  let jobId = null;
  if (record.json.fields && record.json.fields['Job ID']) {
    jobId = record.json.fields['Job ID'];
  } else if (record.json['Job ID']) {
    jobId = record.json['Job ID'];
  }
  if (jobId) existingIds.add(jobId);
}

const netNew = aggregatedJobs.filter(item => !existingIds.has(item.json.jobId));

// Safety brake: cap at 100 new records per run
if (netNew.length > 100) {
  throw new Error(`Safety brake: ${netNew.length} net-new jobs exceeds 100 limit. Review your Tracked Companies title keywords — they may be too broad. Increase the cap in this Code node if this is intentional.`);
}

if (netNew.length === 0) {
  return [{ json: { _empty: true, _message: `${aggregatedJobs.length} jobs found, all already in Pipeline` } }];
}

return netNew;
